**Fix:**
```js
const jwt = require('jsonwebtoken');

function authenticate(req, res, next) {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'Authentication required' });
  try {
    req.user = jwt.verify(token, process.env.JWT_SECRET);
    next();
  } catch (err) {
    return res.status(403).json({ error: 'Invalid or expired token' });
  }
}

app.get('/users', authenticate, (req, res) => {
  // Also consider: strip emails unless the requester has admin role
  res.json(users.map(({ id, name }) => ({ id, name })));
});
```

---

### 3. No Rate Limiting (OWASP A04: Insecure Design)
**Line: Global** — No rate limiter is applied. The server is fully exposed to brute-force attacks, credential stuffing (if auth is added), and denial-of-service.

**Fix:**
```js
const rateLimit = require('express-rate-limit');

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' }
});

app.use(limiter);
```

---

## 🟠 MEDIUM Severity

### 4. No CORS Configuration (OWASP A05: Security Misconfiguration)
**Line: Global** — Express has no default CORS policy, so browser-based cross-origin requests will be blocked — but if CORS is ever needed, it should be explicitly configured rather than using a wildcard `*`.

**Fix:**
```js
const cors = require('cors');

app.use(cors({
  origin: ['https://yourdomain.com'],  // Whitelist specific origins
  methods: ['GET'],
  credentials: true,
}));
```

---

### 5. No Error Handling Middleware (OWASP A05: Security Misconfiguration)
**Line: Global** — Express's default error handler exposes **full stack traces** when `NODE_ENV !== 'production'`. An unhandled error in any route could leak file paths, dependency versions, and internal logic.

**Fix:**
```js
// Place AFTER all route definitions
